     8→const BLP = {
     9→  bg: "./buttons/glue/GlueScreen-Button1-BackdropBackground.blp",
    10→  bgDown: "./buttons/glue/GlueScreen-Button1-BackdropBackground-Down.blp",
    11→  border: "./buttons/glue/GlueScreen-Button1-BorderedBackdropBorder.blp",
    12→  borderDown:
    13→    "./buttons/glue/GlueScreen-Button1-BorderedBackdropBorder-Down.blp",
