    51→interface GlueDropdownProps<T extends string> {
    52→  options: readonly T[];
    53→  value: T;
    54→  onChange: (value: T) => void;
    55→  /** Optional formatter for display text */
    56→  label?: (value: T) => string;
    57→}
    58→
    59→export default function GlueDropdown<T extends string>({
    60→  options,
    61→  value,
    62→  onChange,
    63→  label,
    64→}: GlueDropdownProps<T>) {
    65→  const urls = useBlpUrls();
    66→  const triggerCanvasRef = useRef<HTMLCanvasElement>(null);
    67→  const menuCanvasRef = useRef<HTMLCanvasElement>(null);
    68→  const anchorRef = useRef<HTMLDivElement>(null);
    69→
    70→  const [open, setOpen] = useState(false);
    71→  const [hovered, setHovered] = useState(false);
    72→
    73→  // Close when clicking outside
    74→  useEffect(() => {
    75→    if (!open) return;
    76→    const handler = (e: MouseEvent) => {
    77→      if (anchorRef.current && !anchorRef.current.contains(e.target as Node)) {
    78→        setOpen(false);
    79→      }
    80→    };
    81→    document.addEventListener("mousedown", handler);
    82→    return () => document.removeEventListener("mousedown", handler);
    83→  }, [open]);
    84→
    85→  // Draw trigger button canvas
    86→  useEffect(() => {
    87→    const canvas = triggerCanvasRef.current;
    88→    const bgUrl = open ? urls.bgDown : urls.bg;
    89→    const borderUrl = open ? urls.borderDown : urls.border;
    90→    const hoverActive = hovered && !open;
    91→    if (!canvas || !bgUrl || !borderUrl) return;
    92→    let cancelled = false;
    93→
    94→    void Promise.all([
    95→      loadDataUrlImage(bgUrl),
    96→      loadDataUrlImage(borderUrl),
    97→      urls.hover ? loadDataUrlImage(urls.hover) : Promise.resolve(null),
    98→    ])
    99→      .then(([bgImg, borderImg, hoverImg]) => {
   100→        if (cancelled) return;
   101→        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, hoverImg, hoverActive);
   102→      })
   103→      .catch((err) => console.error(err));
   104→
   105→    return () => {
   106→      cancelled = true;
   107→    };
   108→  }, [open, hovered, urls.bg, urls.bgDown, urls.border, urls.borderDown, urls.hover]);
   109→
   110→  // Draw menu canvas
   111→  useEffect(() => {
   112→    const canvas = menuCanvasRef.current;
   113→    const bgUrl = urls.popupBg || urls.bg;
   114→    const borderUrl = urls.border;
   115→    if (!open || !canvas || !bgUrl || !borderUrl) return;
   116→    let cancelled = false;
   117→
   118→    void Promise.all([loadDataUrlImage(bgUrl), loadDataUrlImage(borderUrl)])
   119→      .then(([bgImg, borderImg]) => {
   120→        if (cancelled) return;
   121→        drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, null, false);
   122→      })
   123→      .catch((err) => console.error(err));
   124→
   125→    return () => {
   126→      cancelled = true;
   127→    };
   128→  }, [open, urls.popupBg, urls.bg, urls.border]);
   129→
   130→  const displayText = label ? label(value) : value;
   131→
   132→  return (
   133→    <div className="popup-trigger-anchor" ref={anchorRef}>
   134→      <button
   135→        type="button"
   136→        className="popup-trigger-button"
   137→        aria-haspopup="listbox"
   138→        aria-expanded={open}
   139→        onMouseEnter={() => setHovered(true)}
   140→        onMouseLeave={() => setHovered(false)}
   141→        onClick={() => setOpen((prev) => !prev)}
   142→      >
   143→        <canvas ref={triggerCanvasRef} className="popup-trigger-canvas" />
   144→        <span className="popup-title-text">{displayText}</span>
   145→        {urls.arrow && (
   146→          <img src={urls.arrow} alt="" className="popup-arrow-icon" />
   147→        )}
   148→      </button>
   149→      {open && (
   150→        <div className="popup-menu-demo" aria-label="Build order selector">
   151→          <canvas ref={menuCanvasRef} className="popup-menu-canvas" />
   152→          {options.map((option) => (
   153→            <div
   154→              key={option}
   155→              role="option"
   156→              aria-selected={value === option}
   157→              className={`popup-menu-option${value === option ? " selected" : ""}`}
   158→              onClick={() => {
   159→                onChange(option);
   160→                setOpen(false);
   161→              }}
   162→            >
   163→              {label ? label(option) : option}
   164→            </div>
   165→          ))}
   166→        </div>
   167→      )}
   168→    </div>
   169→  );
   170→}
