     7→
     8→const BLP = {
     9→  bg: "./buttons/scrollbar/GlueScreen-Scrollbar-BackdropBackground.blp",
    10→  border: "./buttons/scrollbar/GlueScreen-Scrollbar-BackdropBorder.blp",
    11→  up: "./buttons/scrollbar/GlueScreen-Scrollbar-UpArrow.blp",
    12→  down: "./buttons/scrollbar/GlueScreen-Scrollbar-DownArrow.blp",
    13→  knob: "./buttons/scrollbar/SinglePlayerSkirmish-ScrollBarKnob.blp",
    14→};
    15→
    16→const CORNER_RATIO = 0.008 / 0.0165;
    17→const INSET_RATIO = 0.004 / 0.0165;
    18→const THUMB_SIZE = 16;
    19→
    20→interface Urls {
    21→  bg: string;
    22→  border: string;
    23→  up: string;
    24→  down: string;
    25→  knob: string;
    26→}
    27→
    28→function useBlpUrls(): Urls {
    29→  const [urls, setUrls] = useState<Urls>({
    30→    bg: "",
    31→    border: "",
    32→    up: "",
    33→    down: "",
    34→    knob: "",
    35→  });
    36→
    37→  useEffect(() => {
    38→    void Promise.all(Object.values(BLP).map((p) => loadBlpDataUrl(p))).then(
    39→      ([bg, border, up, down, knob]) => {
    40→        setUrls({ bg, border, up, down, knob });
    41→      },
    42→    );
    43→  }, []);
    44→
    45→  return urls;
    46→}
    47→
    48→function thumbTopPercent(value: number, trackPx: number): string {
    49→  if (trackPx <= 0) return "0%";
    50→  const clamped = Math.max(0, Math.min(100, value));
    51→  const min = THUMB_SIZE * 0.5;
    52→  const max = Math.max(min, trackPx - THUMB_SIZE * 0.5);
    53→  const center = min + ((max - min) * clamped) / 100;
    54→  return `${(center / trackPx) * 100}%`;
    55→}
    56→
    57→interface GlueScrollbarProps {
    58→  /** 0–100 scroll percentage */
    59→  value: number;
    60→  onChange: (value: number) => void;
    61→}
    62→
    63→export default function GlueScrollbar({
    64→  value,
    65→  onChange,
    66→}: GlueScrollbarProps) {
    67→  const urls = useBlpUrls();
    68→  const trackRef = useRef<HTMLDivElement>(null);
    69→  const trackCanvasRef = useRef<HTMLCanvasElement>(null);
    70→  const [trackHeight, setTrackHeight] = useState(132);
    71→
    72→  // Measure track height
    73→  useEffect(() => {
    74→    const el = trackRef.current;
    75→    if (!el) return;
    76→    const ro = new ResizeObserver((entries) => {
    77→      for (const entry of entries) {
    78→        setTrackHeight(entry.contentRect.height);
    79→      }
    80→    });
    81→    ro.observe(el);
    82→    setTrackHeight(el.clientHeight);
    83→    return () => ro.disconnect();
    84→  }, []);
    85→
    86→  // Draw track canvas
    87→  useEffect(() => {
    88→    const canvas = trackCanvasRef.current;
    89→    if (!canvas || !urls.bg || !urls.border) return;
    90→    let cancelled = false;
    91→
    92→    void Promise.all([
    93→      loadDataUrlImage(urls.bg),
    94→      loadDataUrlImage(urls.border),
    95→    ])
    96→      .then(([bgImg, borderImg]) => {
    97→        if (cancelled) return;
    98→        const w = canvas.clientWidth || 1;
    99→        drawTemplateNineSliceToCanvas(canvas, bgImg, borderImg, {
   100→          cornerPx: w * CORNER_RATIO,
   101→          insetPx: w * INSET_RATIO,
   102→          tileBackground: true,
   103→          opaqueBaseFill: "#000",
   104→        });
   105→      })
   106→      .catch((err) => console.error(err));
   107→
   108→    return () => {
   109→      cancelled = true;
   110→    };
   111→  }, [urls.bg, urls.border, trackHeight]);
   112→
   113→  const bump = useCallback(
   114→    (delta: number) => {
   115→      onChange(Math.max(0, Math.min(100, value + delta)));
   116→    },
   117→    [value, onChange],
   118→  );
   119→
   120→  return (
   121→    <div className="glue-scrollbar-demo">
   122→      <button
   123→        type="button"
   124→        className="glue-scroll-arrow"
   125→        aria-label="Scroll up"
   126→        onClick={() => bump(-8)}
   127→      >
   128→        {urls.up && <img src={urls.up} alt="" />}
   129→      </button>
   130→      <div className="glue-scroll-track" ref={trackRef}>
   131→        <canvas ref={trackCanvasRef} className="glue-scroll-track-canvas" />
   132→        <div
   133→          className="glue-scroll-thumb"
   134→          style={{
   135→            backgroundImage: urls.knob ? `url("${urls.knob}")` : undefined,
   136→            top: thumbTopPercent(value, trackHeight),
   137→          }}
   138→        />
   139→        <input
   140→          type="range"
   141→          min="0"
   142→          max="100"
   143→          value={value}
   144→          aria-label="Scroll position"
   145→          onChange={(e) => onChange(Number(e.currentTarget.value))}
   146→        />
   147→      </div>
   148→      <button
   149→        type="button"
   150→        className="glue-scroll-arrow"
   151→        aria-label="Scroll down"
   152→        onClick={() => bump(8)}
   153→      >
   154→        {urls.down && <img src={urls.down} alt="" />}
   155→      </button>
   156→    </div>
   157→  );
   158→}
